arguments.command:
SYMFILE="/tmp/symbols/libmonosgen-2.0.so.debug"

# Check which section contains these addresses
aarch64-linux-gnu-readelf -S "$SYMFILE" | grep -E '^\s+\[' | awk '{
  if (NF >= 7) {
    name=$2; addr=$4; size=$6;
    if (addr != "" && size != "") {
      start = strtonum("0x"addr);
      end = start + strtonum("0x"size);
      if (start <= 0x2f4b20 && end > 0x2f4b20)
        printf "0x2f4b20 is in section %s (0x%x - 0x%x)\n", name, start, end;
      if (start <= 0x2f4c84 && end > 0x2f4c84)
        printf "0x2f4c84 is in section %s (0x%x - 0x%x)\n", name, start, end;
    }
  }
}'

echo "---"
# Also try looking up function symbols near these addresses
aarch64-linux-gnu-nm -C --defined-only "$SYMFILE" 2>/dev/null | sort | awk '
  $1 ~ /^[0-9a-f]+$/ {
    addr = strtonum("0x"$1)
    if (addr <= 0x2f4b20) { prev1 = $0; prevaddr1 = addr }
    if (addr <= 0x2f4c84) { prev2 = $0; prevaddr2 = addr }
    if (addr > 0x2f4b20 && !found1) { printf "0x2f4b20 between:\n  %s\n  %s\n", prev1, $0; found1=1 }
    if (addr > 0x2f4c84 && !found2) { printf "0x2f4c84 between:\n  %s\n  %s\n", prev2, $0; found2=1 }
  }
'

